namespace sv_7db62269ca0345019f1e383ad504021f.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_7db62269ca0345019f1e383ad504021f.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-btn" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🔥"];
}

@namespace sv_7db62269ca0345019f1e383ad504021f.Components.Chat

<div class="message-input">
    <textarea class="message-textarea" rows="2"
              placeholder="@Placeholder"
              @bind="_text"
              @onkeydown="HandleKeyDown" />
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter, EditorRequired] public EventCallback<string> OnSubmit { get; set; }

    private string _text = string.Empty;

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(_text)) return;
        var content = _text.Trim();
        _text = string.Empty;
        await OnSubmit.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }
}

@namespace sv_7db62269ca0345019f1e383ad504021f.Components.Chat

<div class="message-bubble" @onmouseenter="() => _hovered = true" @onmouseleave="() => { _hovered = false; _showEmojiPicker = false; }">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            💬 @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">💬 Reply</button>
            <button class="action-btn" @onclick="() => _showEmojiPicker = !_showEmojiPicker" title="Add reaction">😊 React</button>
        </div>

        @if (_showEmojiPicker)
        {
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public sv_7db62269ca0345019f1e383ad504021f.Services.Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
