@namespace sv_7db62269ca0345019f1e383ad504021f.Components.Chat

<div class="message-input">
    <textarea class="message-textarea" rows="2"
              placeholder="@Placeholder"
              @bind="_text"
              @onkeydown="HandleKeyDown" />
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter, EditorRequired] public EventCallback<string> OnSubmit { get; set; }

    private string _text = string.Empty;

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(_text)) return;
        var content = _text.Trim();
        _text = string.Empty;
        await OnSubmit.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }
}

@namespace sv_7db62269ca0345019f1e383ad504021f.Components.Chat

<div class="message-bubble" @onmouseenter="() => _hovered = true" @onmouseleave="() => { _hovered = false; _showEmojiPicker = false; }">
