@namespace sv_7db62269ca0345019f1e383ad504021f.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <span class="quote-author">@RootMessage.Author</span>
            <p class="quote-content">@RootMessage.Content</p>
        </div>
    }

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="message-header">
                    <span class="message-author">@reply.Author</span>
                    <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="message-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread…" ButtonLabel="Reply" OnSubmit="OnSendReply" />
</div>

@code {
    [Parameter] public sv_7db62269ca0345019f1e383ad504021f.Services.Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<sv_7db62269ca0345019f1e383ad504021f.Services.Message> Replies { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback OnClose { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

