@page "/chat"
@using sv_7db62269ca0345019f1e383ad504021f.Services
@using sv_7db62269ca0345019f1e383ad504021f.Components.Chat
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-area @(_threadOpen ? "with-thread" : "")">
        @if (_activeChannel is not null)
        {
            <div class="main-header">
                <h2># @_activeChannel.Name</h2>
                <span class="main-header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }

                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                                   OnOpenThread="OpenThread"
                                   OnReact="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="Message #@_activeChannel.Name"
                          ButtonLabel="Send"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="empty-state">Select a channel to start chatting</div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private Channel? _activeChannel;
    private int? _activeChannelId;
    private Message? _threadRootMessage;
    private bool _threadOpen;
    private bool _loadingMore;
    private bool _allMessagesLoaded;
    private const int PageSize = 30;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadSummaries = new();
        _allMessagesLoaded = false;
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        await LoadThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to clear unread badge
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadOlderMessages()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannelId is null) return;
        _loadingMore = true;

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count < PageSize) _allMessagesLoaded = true;
        _messages.InsertRange(0, older);
        await LoadThreadSummaries();

        _loadingMore = false;
    }

    private async Task LoadThreadSummaries()
    {
        // Build thread summaries from messages that are reply targets
        foreach (var msg in _messages.Where(m => m.ReplyToId is null))
        {
            if (!_threadSummaries.ContainsKey(msg.Id))
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                if (thread.Count > 0)
                {
                    _threadSummaries[msg.Id] = new ThreadSummary(
                        msg.Id,
                        thread.Count,
                        thread.Max(t => t.SentAt));
                }
            }
        }
    }

    private int GetThreadReplyCount(int messageId) =>
        _threadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannelId is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary count
        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id,
            _threadReplies.Count,
            reply.SentAt);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh the affected message
        if (_activeChannelId is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
            _messages = refreshed;
        }
    }

    private async Task HandleScroll()
    {
        // Trigger load-more when scrolled near the top
        await LoadOlderMessages();
    }
}

